<?php declare(strict_types=1);
function render_dispatch_advice(array $d): void { ?><article class="document"><h1>Material Dispatch Advice</h1><p><strong><?=htmlspecialchars((string)$d['dispatch_advice_no'])?></strong> · Status: <?=htmlspecialchars(ucfirst((string)$d['status']))?></p><div class="meta"><p>Quotation: <?=htmlspecialchars((string)$d['quotation_no'])?><br>Agreement: <?=htmlspecialchars((string)$d['agreement_no'])?></p><p>Customer: <?=htmlspecialchars((string)$d['customer_name'])?><br>Mobile: <?=htmlspecialchars((string)$d['customer_mobile'])?></p><p>Planned dispatch: <?=htmlspecialchars((string)$d['planned_dispatch_date'])?><br>Delivery address: <?=nl2br(htmlspecialchars((string)$d['delivery_address']))?></p></div><table><thead><tr><th>#</th><th>Item / description</th><th>Brand / model</th><th>Qty</th><th>Remarks</th></tr></thead><tbody><?php foreach($d['items'] as $i=>$r):?><tr><td><?=$i+1?></td><td><strong><?=htmlspecialchars((string)$r['name'])?></strong><br><?=htmlspecialchars((string)$r['description'])?></td><td><?=htmlspecialchars((string)$r['brand_model'])?></td><td><?=htmlspecialchars((string)$r['qty'])?> <?=htmlspecialchars((string)$r['unit'])?></td><td><?=htmlspecialchars((string)$r['remarks'])?></td></tr><?php endforeach;?></tbody></table><h3>Customer note</h3><p><?=nl2br(htmlspecialchars((string)$d['customer_note']))?></p><p class="disclaimer"><strong>Important:</strong> <?=htmlspecialchars((string)$d['disclaimer'])?></p></article><?php }
